class Reporter:
    """
    Voice of the Council.

    Reporter transforms the Council's separate
    intelligence products into a mission briefing
    for the Observer.
    """

    def brief(self, council_output: dict):

        print()
        print("📢 Reporter")
        print("Mission Brief")
        print("────────────────────────────")
        print()

        recommendations = council_output.get("recommendations", [])
        theories = council_output.get("theories", [])
        reviews = council_output.get("reviews", [])

        if recommendations:
            print("Primary Recommendation")
            print("----------------------")
            for recommendation in recommendations:
                print(f"• {recommendation}")
            print()

        if theories:
            print("Theories")
            print("--------")
            for theory in theories:
                print(f"• {theory['hypothesis']}")
            print()

        if reviews:
            print("Evidence Review")
            print("----------------")
            for review in reviews:
                print(
                    f"• {review['theory']} "
                    f"({review['status']})"
                )

        print()
        print("Observer...")
        print("Awaiting your decision.")